import{_ as t,o as n,c as s,ak as e}from"./chunks/framework.DwHlt8HN.js";const b=JSON.parse('{"title":"分布式事务","description":"","frontmatter":{},"headers":[],"relativePath":"distributed/transaction/index.md","filePath":"distributed/transaction/index.md","lastUpdated":1774319300000}'),d={name:"distributed/transaction/index.md"};function r(i,a,l,p,h,c){return n(),s("div",null,[...a[0]||(a[0]=[e(`<h1 id="分布式事务" tabindex="-1">分布式事务 <a class="header-anchor" href="#分布式事务" aria-label="Permalink to “分布式事务”">​</a></h1><p>一个订单服务调用了库存服务、账户服务、仓储服务。</p><p>四个服务，四个数据库，怎么保证「订单创建成功，库存扣减成功，余额扣减成功，库存入库成功」？</p><p>这就是<strong>分布式事务</strong>要解决的问题。</p><h2 id="模块速览" tabindex="-1">模块速览 <a class="header-anchor" href="#模块速览" aria-label="Permalink to “模块速览”">​</a></h2><p>分布式事务的解决方案分为两大类：强一致性方案和最终一致性方案。</p><table tabindex="0"><thead><tr><th>章节</th><th>篇数</th><th>核心内容</th></tr></thead><tbody><tr><td><a href="/distributed/transaction/solution-overview">解决方案总览</a></td><td>7 篇</td><td>AT、TCC、SAGA、可靠消息、最大努力通知、方案对比</td></tr><tr><td><a href="/distributed/transaction/seata-architecture">原理深度剖析</a></td><td>7 篇</td><td>XA 规范、Seata 架构、全局事务、TCC 问题</td></tr></tbody></table><h2 id="方案对比" tabindex="-1">方案对比 <a class="header-anchor" href="#方案对比" aria-label="Permalink to “方案对比”">​</a></h2><table tabindex="0"><thead><tr><th>方案</th><th>一致性</th><th>侵入性</th><th>性能</th><th>适用场景</th></tr></thead><tbody><tr><td>XA</td><td>强一致</td><td>中等</td><td>差</td><td>多数据库强一致</td></tr><tr><td>AT</td><td>最终一致</td><td>低</td><td>中</td><td>普通业务场景</td></tr><tr><td>TCC</td><td>强一致</td><td>高</td><td>高</td><td>资源敏感场景</td></tr><tr><td>SAGA</td><td>最终一致</td><td>中</td><td>高</td><td>长事务编排</td></tr><tr><td>可靠消息</td><td>最终一致</td><td>低</td><td>高</td><td>异步解耦</td></tr></tbody></table><h2 id="选型决策树" tabindex="-1">选型决策树 <a class="header-anchor" href="#选型决策树" aria-label="Permalink to “选型决策树”">​</a></h2><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>业务代码能改吗？</span></span>
<span class="line"><span>├─ 不能 → AT 模式（零侵入）</span></span>
<span class="line"><span>└─ 能 ↓</span></span>
<span class="line"><span></span></span>
<span class="line"><span>资源敏感吗？（库存、资金）</span></span>
<span class="line"><span>├─ 是 → TCC 模式（高性能）</span></span>
<span class="line"><span>└─ 否 ↓</span></span>
<span class="line"><span></span></span>
<span class="line"><span>事务时间长？（&gt; 1 分钟）</span></span>
<span class="line"><span>├─ 是 → SAGA 模式（长事务）</span></span>
<span class="line"><span>└─ 否 → AT 模式 / 可靠消息</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><h2 id="面试高频问题" tabindex="-1">面试高频问题 <a class="header-anchor" href="#面试高频问题" aria-label="Permalink to “面试高频问题”">​</a></h2><h3 id="q1-分布式事务的解决方案有哪些" tabindex="-1">Q1：分布式事务的解决方案有哪些？ <a class="header-anchor" href="#q1-分布式事务的解决方案有哪些" aria-label="Permalink to “Q1：分布式事务的解决方案有哪些？”">​</a></h3><blockquote><p>「五种：XA、AT、TCC、SAGA、可靠消息。 XA 是数据库层面的强一致，性能差但可靠。 AT 是 Seata 的零侵入方案，通过 undolog 自动补偿。 TCC 是业务层面的强一致，性能高但侵入性大。 SAGA 适合长事务，通过补偿操作实现最终一致。 可靠消息通过 MQ 保证最终一致，性能最高但延迟大。」</p></blockquote><h3 id="q2-tcc-的空回滚、幂等、悬挂问题怎么解决" tabindex="-1">Q2：TCC 的空回滚、幂等、悬挂问题怎么解决？ <a class="header-anchor" href="#q2-tcc-的空回滚、幂等、悬挂问题怎么解决" aria-label="Permalink to “Q2：TCC 的空回滚、幂等、悬挂问题怎么解决？”">​</a></h3><blockquote><p>「三个问题的本质都是分布式系统的经典问题： 空回滚——用 Try 执行记录解决，Cancel 前检查记录是否存在。 幂等——用唯一键 + 状态机解决，无论执行多少次结果一致。 悬挂——用状态转移检查解决，Cancel 前确认是否已 Confirm。」</p></blockquote><h3 id="q3-seata-at-模式的全局锁和数据库锁有什么区别" tabindex="-1">Q3：Seata AT 模式的全局锁和数据库锁有什么区别？ <a class="header-anchor" href="#q3-seata-at-模式的全局锁和数据库锁有什么区别" aria-label="Permalink to “Q3：Seata AT 模式的全局锁和数据库锁有什么区别？”">​</a></h3><blockquote><p>「数据库锁防止并发事务之间的脏写，Seata 全局锁防止跨全局事务的脏写。 两者的作用域不同，数据库锁是单节点内的，Seata 全局锁是跨节点的。 两者配合，共同保证隔离性。」</p></blockquote><h2 id="延伸阅读" tabindex="-1">延伸阅读 <a class="header-anchor" href="#延伸阅读" aria-label="Permalink to “延伸阅读”">​</a></h2><p>分布式事务没有银弹，每种方案都是一致性、性能、开发成本的权衡。</p><p>建议结合具体业务场景理解：</p><ul><li>电商下单：TCC（库存/余额）+ AT（订单）+ 可靠消息（通知）</li><li>金融转账：TCC（强一致）</li><li>订单流水线：SAGA（长事务）</li></ul>`,22)])])}const u=t(d,[["render",r]]);export{b as __pageData,u as default};
